    qrCodeData = new QrCodeData(list, arrayList2, 
        uri.getQueryParameter("name"),       // deviceName — no validation
        uri.getQueryParameter("tenant_id"),   // deviceTenantId — no validation
        queryParameter2);                     // deviceIdentity — no validation
}
if (qrCodeData == null) {
